import java.util.*;

class LUPrefix {

    private TreeSet<Integer> uploadedVideos;
    private int longestPrefix;

    public LUPrefix(int n) {
        uploadedVideos = new TreeSet<>();
        longestPrefix = 0;
    }

    public void upload(int video) {
        uploadedVideos.add(video);
        while (uploadedVideos.contains(longestPrefix + 1)) {
            longestPrefix++;
        }
    }

    public int longest() {
        return longestPrefix;
    }
}

